INSERT INTO public.ui_builder_snapshots (id, project_id, slug, title, files, message_id, created_at) VALUES ('b4090843-ee59-4c21-b8af-ec3ac95128da', '35cbad53-43ee-4f1c-9bf0-48cc2630bcd7', 'snap-0003', '작품 제목 변경하기', '{"/App.tsx": "import React from ''react'';\n\nconst image = {\n  id: 1,\n  src: ''https://images.unsplash.com/photo-1555685813-47032115f6ab?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=MnwxMTc3N3wwfDF8c2VhcmNofDJ8fGFydCUyMHBvc3R8ZW58MHx8fHwxNjcwNDM1MjAw&ixlib=rb-1.2.1&q=80&w=400'',\n  title: ''명작 1'',\n  description: ''이것은 우리의 시대를 대변하는 명작입니다.'',\n  author: ''작가 A'',\n};\n\nconst App: React.FC = () => {\n  return (\n    <div className=\"flex flex-col items-center p-6 bg-gradient-to-br from-yellow-200 to-orange-300 min-h-screen\">\n      <h1 className=\"text-5xl font-bold text-gray-800 mb-8\">🎨 예술 갤러리</h1>\n      <p className=\"text-xl text-gray-600 mb-6 text-center w-full max-w-2xl\">\n        이 작품은 우리의 시대를 표현한 예술입니다.\n      </p>\n      <div className=\"bg-white rounded-lg overflow-hidden shadow-lg max-w-md\">\n        <img\n          src={image.src}\n          alt={image.title}\n          className=\"w-full h-48 object-cover\"\n        />\n        <div className=\"p-4\">\n          <h2 className=\"text-xl font-semibold\">{image.title}</h2>\n          <p className=\"text-gray-600\">{image.description}</p>\n          <p className=\"text-gray-500 italic\">{image.author}</p>\n        </div>\n      </div>\n    </div>\n  );\n};\n\nexport default App;\n"}', '895a2149-a9dd-40c2-b82a-0be6d874396b', '2026-04-18 00:51:45.315274+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.ui_builder_snapshots (id, project_id, slug, title, files, message_id, created_at) VALUES ('8b88c145-b9e6-4047-be43-3b1dc09dfa82', '35cbad53-43ee-4f1c-9bf0-48cc2630bcd7', 'snap-0004', '오늘의 날씨 화면 만들기', '{"/App.tsx": "import React, { useState } from ''react'';\n\nconst App: React.FC = () => {\n  const [location, setLocation] = useState(''서울'');\n  const [temperature, setTemperature] = useState(''25°C'');\n  const [condition, setCondition] = useState(''맑음'');\n  const [description, setDescription] = useState(''오늘은 맑고 기온이 적당합니다.'');\n\n  return (\n    <div className=\"flex flex-col items-center justify-center h-screen p-6 bg-gradient-to-br from-blue-200 to-blue-500\">\n      <h1 className=\"text-4xl font-bold text-white mb-4\">🌤️ 오늘의 날씨</h1>\n      <div className=\"bg-white rounded-lg shadow-lg p-6 w-full max-w-md text-center\">\n        <h2 className=\"text-2xl font-semibold mb-2\">{location}</h2>\n        <p className=\"text-3xl font-bold text-blue-600\">{temperature}</p>\n        <p className=\"text-xl text-gray-700\">{condition}</p>\n        <p className=\"text-gray-600 mt-2\">{description}</p>\n      </div>\n    </div>\n  );\n};\n\nexport default App;\n"}', 'c0bc9f79-7429-44e5-8061-41e8122adcdf', '2026-04-19 03:50:45.180638+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.ui_builder_snapshots (id, project_id, slug, title, files, message_id, created_at) VALUES ('481cd8be-1d66-496b-8c14-8e642fb5db25', '35cbad53-43ee-4f1c-9bf0-48cc2630bcd7', 'snap-0005', '미세먼지 상태 화면 구성', '{"/App.tsx": "import React from ''react'';\n\nconst App: React.FC = () => {\n  const dustLevel = ''보통''; // 미세먼지 수준 (예: 좋음, 보통, 나쁨)\n  const pm10 = 40; // PM10 수치\n  const pm25 = 25; // PM2.5 수치\n  const statusDescription = ''미세먼지 농도가 보통입니다. 외출 시 주의가 필요합니다.''; // 상태 설명\n\n  return (\n    <div className=\"flex flex-col items-center justify-center h-screen p-6 bg-gradient-to-br from-green-200 to-yellow-300\">\n      <h1 className=\"text-4xl font-bold text-gray-800 mb-4\">🌫️ 미세먼지 정보</h1>\n      <div className=\"bg-white rounded-lg shadow-lg p-6 w-full max-w-md text-center\">\n        <h2 className=\"text-2xl font-semibold mb-2\">현재 미세먼지 수준</h2>\n        <p className=\"text-3xl font-bold text-blue-600 mb-2\">{dustLevel}</p>\n        <p className=\"text-lg text-gray-700\">PM10: {pm10} µg/m³</p>\n        <p className=\"text-lg text-gray-700\">PM2.5: {pm25} µg/m³</p>\n        <p className=\"text-gray-600 mt-2\">{statusDescription}</p>\n      </div>\n    </div>\n  );\n};\n\nexport default App;\n"}', '557328df-1110-4bdb-9331-42abeb7b1919', '2026-04-19 13:37:43.086647+00') ON CONFLICT (id) DO NOTHING;

