INSERT INTO public.ui_builder_messages (id, project_id, role, content, tokens_in, tokens_out, created_at, ui_calls, scope, dashboard_id) VALUES ('0605493f-fb01-48c5-b772-3bcce9d255f0', '35cbad53-43ee-4f1c-9bf0-48cc2630bcd7', 'assistant', '아래는 로그인 폼을 포함하고, 버튼을 누르면 "Hello World"가 출력되는 React + TypeScript 코드입니다. 

import React, { useState } from ''react'';

const App: React.FC = () => {
  const [name, setName] = useState('''');
  const [message, setMessage] = useState('''');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setMessage(`Hello World, ${name}!`);
  };

  return (
    <div className="flex flex-col items-center justify-center h-screen">
      <form onSubmit={handleSubmit} className="flex flex-col space-y-4">
        <input
          type="text"
          placeholder="Enter your name"
          value={name}
          onChange={(e) => setName(e.target.value)}
          className="border p-2 rounded"
        />
        <button type="submit" className="bg-blue-500 text-white p-2 rounded">Submit</button>
      </form>
      {message && <h1 className="mt-4">{message}</h1>}
    </div>
  );
};

export default App;

위 코드를 사용하면 사용자가 이름을 입력하고 버튼을 클릭할 때 "Hello World" 메시지가 표시됩니다.', NULL, NULL, '2026-04-17 18:31:03.850586+00', '[]', 'project', NULL) ON CONFLICT (id) DO NOTHING;
