INSERT INTO public.ui_builder_messages (id, project_id, role, content, tokens_in, tokens_out, created_at, ui_calls, scope, dashboard_id) VALUES ('253a1bf2-c397-4909-a339-e57db4be730f', '35cbad53-43ee-4f1c-9bf0-48cc2630bcd7', 'assistant', '아래는 로그인 폼을 포함하고, 버튼을 누르면 "헬로 월드"가 출력되는 React + TypeScript 코드입니다.

import React, { useState } from ''react'';

const App: React.FC = () => {
  const [name, setName] = useState('''');
  const [message, setMessage] = useState('''');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setMessage(`헬로 월드, ${name}님!`);
  };

  return (
    <div className="flex flex-col items-center justify-center h-screen">
      <form onSubmit={handleSubmit} className="flex flex-col space-y-4">
        <input
          type="text"
          placeholder="이름을 입력하세요"
          value={name}
          onChange={(e) => setName(e.target.value)}
          className="border p-2 rounded"
        />
        <button type="submit" className="bg-blue-500 text-white p-2 rounded">제출</button>
      </form>
      {message && <h1 className="mt-4">{message}</h1>}
    </div>
  );
};

export default App;

