          type="text"
          placeholder="이름을 입력하세요"
          value={name}
          onChange={(e) => setName(e.target.value)}
          className="border p-2 rounded mb-4 focus:outline-none focus:ring-2 focus:ring-blue-400"
        />
        <textarea
          placeholder="글을 작성하세요"
          value={message}
          onChange={(e) => setMessage(e.target.value)}
          className="border p-2 rounded mb-4 focus:outline-none focus:ring-2 focus:ring-blue-400"
          rows={4}
        />
        <button type="submit" className="bg-blue-500 text-white p-2 rounded hover:bg-blue-600 transition">작성하기</button>
      </form>

      <div className="grid grid-cols-1 gap-4 w-full max-w-md mb-8">
        {entries.map((entry, index) => (
          <div key={index} className="bg-white p-5 rounded-lg shadow-md transition transform hover:scale-105">
            <h3 className="font-semibold text-gray-800 text-xl">{entry.name}</h3>
            <p className="text-gray-600 mt-2">{entry.message}</p>
